const { responses, survey_title, question } = $input.first().json;
// Compute basic NPS stats without LLM
const scores = responses.map(r => r.nps_score).filter(s => typeof s === 'number');
const promoters = scores.filter(s => s >= 9).length;
const passives = scores.filter(s => s >= 7 && s <= 8).length;
const detractors = scores.filter(s => s <= 6).length;
const total = scores.length;
const nps = total > 0 ? Math.round(((promoters - detractors) / total) * 100) : 0;
// Prepare LLM prompt
const responseText = responses.map(r => `  [${r.id}|NPS:${r.nps_score}] ${r.open_text}`).join('\n');
const system = `You are a UX researcher analysing open-text survey responses. You identify recurring themes, extract actionable insights, and flag critical issues. You quote directly from responses when possible. Return ONLY valid JSON.`;
const user = `Analyse these ${total} survey responses for: "${survey_title}"
Question: "${question}"

NPS stats: Promoters ${promoters} | Passives ${passives} | Detractors ${detractors} | NPS: ${nps}

Responses:
${responseText}

Return JSON:
{
  "themes": [
    { "theme": "string", "sentiment": "positive|negative|mixed", "frequency": 4, "representative_quotes": ["string"], "response_ids": ["R001"], "actionable": true }
  ],
  "top_3_insights": ["string — specific, actionable insight with evidence"],
  "critical_issues": ["string — things causing detractors that need immediate attention"],
  "delight_signals": ["string — things promoters love that should be protected"],
  "feature_requests": [{ "request": "string", "frequency": 2, "response_ids": ["string"] }],
  "recommended_actions": [{ "action": "string", "priority": "high|medium|low", "rationale": "string" }]
}`;
return [{ json: { responses, survey_title, question, nps_stats: { nps, promoters, passives, detractors, total }, system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Compute NPS & Prepare Prompt').first().json;
let parsed;
try {
  const c = response.choices?.[0]?.message?.content;
  if (!c) throw new Error('No content');
  parsed = JSON.parse(c);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
if (!parsed.themes || !Array.isArray(parsed.themes)) return [{ json: { _error: true, reason: 'Missing themes' } }];
return [{ json: { _error: false, analysis: parsed, nps_stats: upstream.nps_stats, meta: { survey_title: upstream.survey_title, total: upstream.nps_stats.total, generated_at: new Date().toISOString() } } }];
